$(function(){
    var w = window.screen.width;
    if (w<600) {
         $("#removeimg").remove();
         $(".kf01").remove();
         $(".kf02").remove();
         $(".kf03").remove();
         $("link[href='/css/kf02.css']").remove();
         $("script[src='/css/kf02.js']").remove();
    }
    
     $('#pmclose').click(function () {
        // $(this).hide();
        $(".pm01-full-screen-img").hide()
    })
   
})

